import React from "react"
import Select from 'react-select'
import { properties } from '../../properties/properties.js'
import querystring from 'query-string'
import { Chart as ChartJS, registerables } from 'chart.js';
import { Bar } from 'react-chartjs-2'

ChartJS.register(...registerables);

class Report extends React.Component {


    constructor(props) {
        super(props);
        this.state = {
            results: [], screen: 0, selectedYear: []
        };
    }

    handleYearChange = (selectedOptions) => {
        this.setState({selectedYear: selectedOptions})
      }




      componentDidMount() {



        this.setState({screen: 0})

        let headers = new Headers();

        headers.append('Content-Type', 'application/json');
        headers.append('Accept', 'application/json');

        fetch(properties.backend + `educationOption`, {
            "method": "GET",
            headers: headers
          })
          .then(response => response.json())
          .then(response => {

            this.setState({results: response})
            this.setState({screen: 1})


          })
          .catch(err => {
            console.log(err);
          });

      }






          render() {


            var header = "Loading ..."




            if (this.state.screen === 1) {
              header = ""
              var content = []


              const yearOptions = []

                this.state.results.year.map(rec => {
                    yearOptions.push({value: rec.survey_year, label: rec.survey_year})
                })


                content.push(<div style={{marginTop: "5px", display: "block"}}><Select isMulti name="year" value={this.state.selectedYear} options={yearOptions} onChange={this.handleYearChange}/></div>)


          }



            return (
<div style={{minHeight: "500px", marginLeft: "50px", marginRight: "50px"}}><h2 className="display-4 text-center">{header}</h2>{content}</div>

            );
          }


  };

  export default Report
